const Q_PHYSICS_2020_MODEL_I=[{"id": "objective>Physics>2020 Model I>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The unit of momentum is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Js<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ns</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ns<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Nms</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall:Momentum= mass ∗ Velocity=Kgms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> N.B Change in Momentum=Force ∗ Time <br/> ∆P=Ft <br/> ⇒The unit of momentum can also be =Ns</div>", "topic": "MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>2020 Model I>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The forces 3N and 4N act on a body in directions due north and due east respectively. Calculate their equilibrant </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5N,53<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> east of north </div>", "<div style=\"font-family:Cambria;font-size:17px;\">5N,53<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> west of south</div>", "<div style=\"font-family:Cambria;font-size:17px;\">5N,37<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> north of east </div>", "<div style=\"font-family:Cambria;font-size:17px;\">7N,37<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> south of west</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagramatically <br/> <img src=\"2020 Model I/phy202.jpg\" style=\"position:relative;max-width:100%;\"/> <br/> The equilibrant force is a force which is needed to keep two or more forces in equilibrium.It has the same magnitude has the resultant but acts in opposite direction. <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 4<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> + 3<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/>  <br/> R<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> = 25 <br/>  <br/> R=5N <br/>  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">θ=</td><td style=\"text-align:center;\">tan<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></td><td style=\"text-align:center;\">3<hr size=\"1\" />4</td></tr></table></div> <br/> =37<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> <br/>  <br/> = θ = ⋉(vertically opposite angles) <br/>  <br/> β = 90 - ⋉ <br/>  <br/> β = 90<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> - 37<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> = 53<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> <br/>  <br/> ∴ The equilibrant force = 5N, S53<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>W  </div>", "topic": "EQUILIBRIUM OF FORCES : EQUILIBRIUM OF PARTICLES"}, {"id": "objective>Physics>2020 Model I>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The distance moved by a particle in the sixth and eighth seconds of the motion are 45m and 53m respectively. Determine the acceleration and initial speed. <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">μ=23ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>,a=3ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">μ=17ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, a=4ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">μ=23ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>,a=4ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">μ=17ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>,3ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It should be noted that the distance covered at the nth seconds is given as:distance at t=n- distance at t=n-1----------------------∗ <br/> =The distance covered at the sixth second  <br/> =S(at t=6s) - S(at t=5s) <br/> S=ut +<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2</span>at<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>--------------------------------1 <br/> ∴45=u(6)+1/2a(6)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>- u(5)+<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2</span>a(5)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> 45=(6u+18a)-(5u + 12.5a) <br/> 45=6u + 18a - 5u - 12.5a <br/> 45=u+5.5a----------------------------2 <br/> =The distance covered at the eigth second <br/> =S(at t=8s) - S(at t=7s) <br/> S=ut+1/2at<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>-------------------3 <br/> ∴53= u(8)+1/2a(8)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> - u(7) + 1/2a(7)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> 53=(8u + 32a) - (7u + 24-5a) <br/> 53= u + 7.5a------------------------4 <br/> Combine equation 2 and 4 <br/> 45= u + 5.5a------------------------2 <br/> -53=u + 7.5a------------------------4 <br/> Subtract 4 from 2 <br/> -8 = -2.0a <br/> a=4.0m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> Sub for a= 4.0m/s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> in 2 <br/> 45= u + 5.5(4) <br/> 45 = u + 22 <br/> u =23.0m/s <br/>  <br/> </div>", "topic": "MOTION: LINEAR MOTION"}, {"id": "objective>Physics>2020 Model I>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A satellite of mass 1000kg orbits the earth at a height of 4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span> m above the earth's center, calculate the gravitational force on the satellite by the earth. (G = 6.67 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span> Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>/kg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>, m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = 5.97 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">24</span> kg)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">249N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">24.9N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">24.8N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">251N</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">r = 4 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">7</span>m <br/> m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span> = 1000kg <br/> m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> = 5.97 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">24</span> kg <br/> G = 6.67 × 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-11</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>kg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">Gm<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span>m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span><hr size=\"1\" />r<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td></tr></table></div> <br/> F = <span class = \"katex\"><span class = \"katex-mathml\"><math xmlns = \"http://www.w3.org/1998/Math/MathML\"><semantics><mrow><mfrac><mrow><mn>6.67</mn><mo>×</mo><mn>1</mn><msup><mn>0</mn><mrow><mo>−</mo><mn>11</mn></mrow></msup><mo>×</mo><mn>1000</mn><mo>×</mo><mn>5.97</mn><mo>×</mo><mn>1</mn><msup><mn>0</mn><mn>24</mn></msup></mrow><msup><mrow><mo fence = \"true\">(</mo><mn>4</mn><mo>×</mo><mn>1</mn><msup><mn>0</mn><mn>7</mn></msup><mo fence = \"true\">)</mo></mrow><mn>2</mn></msup></mfrac></mrow><annotation encoding = \"application/x-tex\">\\frac{6.67×10^{-11}×1000×5.97×10^{24}}{\\left(4×10^{7}\\right)^{2}}</annotation></semantics></math></span><span class = \"katex-html\" aria-hidden = \"true\"><span class = \"base\"><span class = \"strut\" style = \"height:1.6031em;vertical-align:-0.5852em;\"></span><span class = \"mord\"><span class = \"mopen nulldelimiter\"></span><span class = \"mfrac\"><span class = \"vlist-t vlist-t2\"><span class = \"vlist-r\"><span class = \"vlist\" style = \"height:1.0179em;\"><span style = \"top:-2.5898em;\"><span class = \"pstrut\" style = \"height:3em;\"></span><span class = \"sizing reset-size6 size3 mtight\"><span class = \"mord mtight\"><span class = \"minner mtight\"><span class = \"minner mtight\"><span class = \"mopen mtight delimcenter\" style = \"top:0em;\"><span class = \"mtight\">(</span></span><span class = \"mord mtight\">4</span><span class = \"mbin mtight\">×</span><span class = \"mord mtight\">1</span><span class = \"mord mtight\"><span class = \"mord mtight\">0</span><span class = \"msupsub\"><span class = \"vlist-t\"><span class = \"vlist-r\"><span class = \"vlist\" style = \"height:0.7463em;\"><span style = \"top:-2.786em;margin-right:0.0714em;\"><span class = \"pstrut\" style = \"height:2.5em;\"></span><span class = \"sizing reset-size3 size1 mtight\"><span class = \"mord mtight\"><span class = \"mord mtight\">7</span></span></span></span></span></span></span></span></span><span class = \"mclose mtight delimcenter\" style = \"top:0em;\"><span class = \"mtight\">)</span></span></span><span class = \"msupsub\"><span class = \"vlist-t\"><span class = \"vlist-r\"><span class = \"vlist\" style = \"height:0.8575em;\"><span style = \"top:-2.8971em;margin-right:0.0714em;\"><span class = \"pstrut\" style = \"height:2.5em;\"></span><span class = \"sizing reset-size3 size1 mtight\"><span class = \"mord mtight\"><span class = \"mord mtight\">2</span></span></span></span></span></span></span></span></span></span></span></span><span style = \"top:-3.23em;\"><span class = \"pstrut\" style = \"height:3em;\"></span><span class = \"frac-line\" style = \"border-bottom-width:0.04em;\"></span></span><span style = \"top:-3.394em;\"><span class = \"pstrut\" style = \"height:3em;\"></span><span class = \"sizing reset-size6 size3 mtight\"><span class = \"mord mtight\"><span class = \"mord mtight\">6.67</span><span class = \"mbin mtight\">×</span><span class = \"mord mtight\">1</span><span class = \"mord mtight\"><span class = \"mord mtight\">0</span><span class = \"msupsub\"><span class = \"vlist-t\"><span class = \"vlist-r\"><span class = \"vlist\" style = \"height:0.8913em;\"><span style = \"top:-2.931em;margin-right:0.0714em;\"><span class = \"pstrut\" style = \"height:2.5em;\"></span><span class = \"sizing reset-size3 size1 mtight\"><span class = \"mord mtight\"><span class = \"mord mtight\">−</span><span class = \"mord mtight\">11</span></span></span></span></span></span></span></span></span><span class = \"mbin mtight\">×</span><span class = \"mord mtight\">1000</span><span class = \"mbin mtight\">×</span><span class = \"mord mtight\">5.97</span><span class = \"mbin mtight\">×</span><span class = \"mord mtight\">1</span><span class = \"mord mtight\"><span class = \"mord mtight\">0</span><span class = \"msupsub\"><span class = \"vlist-t\"><span class = \"vlist-r\"><span class = \"vlist\" style = \"height:0.8913em;\"><span style = \"top:-2.931em;margin-right:0.0714em;\"><span class = \"pstrut\" style = \"height:2.5em;\"></span><span class = \"sizing reset-size3 size1 mtight\"><span class = \"mord mtight\"><span class = \"mord mtight\">24</span></span></span></span></span></span></span></span></span></span></span></span></span><span class = \"vlist-s\">​</span></span><span class = \"vlist-r\"><span class = \"vlist\" style = \"height:0.5852em;\"><span></span></span></span></span></span><span class = \"mclose nulldelimiter\"></span></span></span></span></span> <br/> F = 249 N</div>", "topic": "GRAVITATIONAL FIELD"}, {"id": "objective>Physics>2020 Model I>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram shows a uniform meter rule AB which balances horizontally at the 90cm mark when a mass of 0.2kg is suspended from B. Calculate the mass of the meter rule. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.05kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.20kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.80kg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.00kg</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Note that the question focuses on a \"uniform\" metre rule. it should be borne in mind that the centre of mass of a uniform metre rule is at the centre(i.e50cm) <br/> <img src=\"2020 Model I/phy205s.jpg\" style=\"position:relative;max-width:100%;\"/> <br/> Taking moment about the pivot <br/> W∗40 = 2∗10 <br/> 40W= 20 <br/> W=0.5N <br/> Recall: W=mg <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m=</td><td style=\"text-align:center;\">W<hr size=\"1\" />g</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.5<hr size=\"1\" />10</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.05kg</td></tr></table></div> </div>", "topic": "EQUILIBRIUM OF FORCES : PRINCIPLES OF MOMENTS"}, {"id": "objective>Physics>2020 Model I>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Starting from rest, a car of mass 1000kg accelerates steadily to 20ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> in 10s. The average power developed in the time period is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.2KW</div>", "<div style=\"font-family:Cambria;font-size:17px;\">20kW</div>", "<div style=\"font-family:Cambria;font-size:17px;\">10kW</div>", "<div style=\"font-family:Cambria;font-size:17px;\">15KW</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given∴ <br/> Initial velocity, u=20m/s <br/> Final velocity, v=20m/s <br/> time, t =10s <br/> mass, m= 1000kg <br/> Power, P=unknown <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:Power=</td><td style=\"text-align:center;\">Energy<hr size=\"1\" />time</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">In</td><td style=\"text-align:center;\">this</td><td style=\"text-align:center;\">case,</td><td style=\"text-align:center;\">P</td><td style=\"text-align:center;\">=K.E<hr size=\"1\" />t</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1/2mv<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />t</td><td style=\"text-align:center;\">=1/2∗1000∗20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />10</td><td style=\"text-align:center;\"></td></tr></table></div>=P=50(400) = 20kw</div>", "topic": "WORK, ENERGY AND POWER: POWER"}, {"id": "objective>Physics>2020 Model I>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the diagram above, the hanging mass m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is adjusted untill m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> is on the verge of sliding. The coefficient of static friction between mass m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> and the table is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span><hr size=\"1\" />m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>g<hr size=\"1\" />m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>g/m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Note that mass m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> is at the verge(or point) of sliding. <br/> Therefore, the acceleration(a) is still equal to zero <br/> ⇒T - NR<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> =m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>a <br/>     T - NR<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> =m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>(0) <br/>      T = NR<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>----------------* <br/> Since, R=mg, <br/>             T=Nm<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>g-------------1 <br/> For the second mass,m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> W<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> - T = m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>a <br/> N.B:a=0 <br/> ∴m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>g - T=m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(0) <br/> m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>g - T= 0  <br/> m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>g = T <br/> Equate 1 and 2 <br/> ∴Nm<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>g= m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>g <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=N</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><hr size=\"1\" />m<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td></tr></table></div></div>", "topic": "FRICTION~~MOTION : NEWTON’S LAWS OF MOTION"}, {"id": "objective>Physics>2020 Model I>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following instruments, in its normal use, serves as a first class lever?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Pair of scissors </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a pair of sugar tongs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a bottle opener</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a knife</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A pair of scissors is a first class lever. Nut cracker is a second class lever while tongs, bottle opener and knife are third class lever.</div>", "topic": "SIMPLE MACHINES"}, {"id": "objective>Physics>2020 Model I>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A stone of mass 5g is projected with a rubber catapult. If the catapult is stretched through a distance of 7cm by an average force of 70N, calculate the speed of the stone at the time of release </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">7.0m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.13m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">31.3m/s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.07m/s</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">It should be noted that the elastic potential energy of the rubber is converted into the kinetic energy of the stone. <br/> 1/2Fe = 1/2mv<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> Fe = mv<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> 70(0.07) = 0.05v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> 70(7) = 0.5v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> 490 = 0.5v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> <br/> v<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>=980 <br/> v= 31.3m/s</div>", "topic": "ELASTICITY : WORK DONE IN SPRINGS AND ELASTIC STRINGS"}, {"id": "objective>Physics>2020 Model I>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What is the height of the liquid column in a barometer tube that would support an atmospheric pressure of 102,000Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> if the density of the liquid is 2600kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> (g=10m/s)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.75m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.76m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.92m</div>", "<div style=\"font-family:Cambria;font-size:17px;\">39.23m</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given: <br/> Atmospheric pressure,Pa = 102,000Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> <br/> Density of liquid,Ρ =2600kgm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> g= 10.0ms<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>;height,h=unknown <br/> Recall:P=ρgh-----------1 <br/> =102,000= 2600∗10∗h <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">h=</td><td style=\"text-align:center;\">102,000<hr size=\"1\" />26,000</td></tr></table></div> <br/> h=3.92m</div>", "topic": "PRESSURE : PRESSURE IN LIQUIDS"}, {"id": "objective>Physics>2020 Model I>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The air in the stem of a mercury in glass thermometer should be expelled before introducing mercury so that </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Enough mercury may enter the bulb</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The glass of the bulb may not crack if the mercury expands to compress the air</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The mercury may not evaporate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The mercury rise in the tube may not be subjected to varying air pressure</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The air in the stem of a mercury in glass thermometer should be expelled before introducing mercury so that the mercury rise in the tube may not be subjected to varying air pressure. If there is air in the stem, it can compress or expand due to changes in temperature, which would affect the pressure on the mercury and therefore the height of the mercury column. This would make the thermometer readings inaccurate.</div>", "topic": "TEMPERATURE AND ITS MEASUREMENT"}, {"id": "objective>Physics>2020 Model I>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A steel wire of 2.0mm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> cross section is held straight(but under no tension) by attaching it firmly to two points at a distance of 1.50m apart at 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C. If the temperature decreases to -10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C and the two points remain fixed, what will be the tension in the wire? <br/> [Ϫ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">s</span>=1.1 ∗ 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-5</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, E=2.0 ∗ 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">11</span>Nm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.176N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">176.0KN</div>", "<div style=\"font-family:Cambria;font-size:17px;\">264.0N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.176KN</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall:E</td><td style=\"text-align:center;\">=F/A<hr size=\"1\" />∆L/L</td><td style=\"text-align:center;\">-----------------1</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∆L<hr size=\"1\" />L</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F/A<hr size=\"1\" />E</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∆L<hr size=\"1\" />L</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">F<hr size=\"1\" />AE</td><td style=\"text-align:center;\">;</td><td style=\"text-align:center;\">∆L</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">FL<hr size=\"1\" />AE</td><td style=\"text-align:center;\">-------------------2</td></tr></table></div> <br/> recall; ⋉ = ∆L/L∆θ ; ∆L= ϪL∆θ -------------------3 <br/> Equate equations 2 and 3 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">FL<hr size=\"1\" />AE</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">⋉L∆θ----------------4</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F∗1.50<hr size=\"1\" />4∗10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span></td></tr></table></div> <br/> =6.6 ∗ 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-4</span> <br/> =1.50F = 264 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">F=</td><td style=\"text-align:center;\">264<hr size=\"1\" />1.5</td></tr></table></div> = 176.0N = 0.176KN</div>", "topic": "ELASTICITY~~HEAT TRANSFER: LINEAR EXPANSIVITY"}, {"id": "objective>Physics>2020 Model I>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A uniform narrow-bored tube closed at one end, contains some dry air which is sealed by a thread of mercury 15.0cm long. When the tube is held vertically, with the closed end at the bottom, the air column is 20.0cm long, but when it is held horizontally, the air column is 24.0cm long. calculate the atmospheric pressure. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.75cmHg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">76cmHg</div>", "<div style=\"font-family:Cambria;font-size:17px;\">75cmHg </div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.76cmHg</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Recall: <br/> <img src=\"2020 Model I/phy2013.jpg\" style=\"position:relative;max-width:100%;\"/> <br/> From Boyle's law <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>=P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>= [P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span> + P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span>----------* <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>= [P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span>]---------** <br/> Recall:P=ρgh-----------1 <br/> N.B:ρ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span>=ρghm <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span>= Pressure due to the atmosphere <br/> P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span>= Pressure due to mercury <br/> =P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span> + P<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span>= ρg(h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span> + h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span> = h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> Recall:V=Ah <br/> Volume of air column= Area of tube ∗ height <br/> N.B: The area of the tube, A is constant <br/> =V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>= A ∗ h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> =A ∗ h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> (h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span> + h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span>) =A ∗ h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> ( h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span>) <br/> h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>(h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span>) +h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">m</span> = h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> (h<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">a</span>) <br/> vertically                       horizontally <br/> 20(H + 15) = 24H <br/> 20H + 300 =24H <br/> 4H=300 <br/> H=75.0cmHg </div>", "topic": "GAS LAWS"}, {"id": "objective>Physics>2020 Model I>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A metal block of mass 2.5kg was heated from 20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C  to 80<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C in 30minutes using a 120W heater. Calculate the specific heat capacity of the metal assuming there is no heat losses.  </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">720Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">960Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1440Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">1600Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span> <br/> </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given <br/> mass,m= 2.5kg <br/> θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>=20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C <br/> θ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>=80<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>C <br/> time, t= 30minutes = 1800s <br/> SHC, C = unknown <br/> Power, p= 120W <br/> Recall:H=mc∆θ----------------1 <br/>             H= P ∗ t -----------------2 <br/> ∴ P ∗ t =mc∆θ <br/> 120 ∗ 1800 =2.5 ∗ C (60) <br/> 120 ∗ 30 = 2.5C  <br/> C= 120 ∗ 12 <br/> C= 1440Jkg<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>k<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "topic": "QUANTITY OF HEAT : HEAT CAPACITY AND SPECIFIC HEAT CAPACITY"}, {"id": "objective>Physics>2020 Model I>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following occurs when a substance solidifies?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The latent heat of fusion is absorbed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">There is rise in temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The latent heat of fusion is given off</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The specific latent heat is given off</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When a substance solidifies, it changes from a liquid state to a solid state. During this process, the substance releases heat. This heat is known as the latent heat of fusion. Therefore, the latent heat of fusion is given off when a substance solidifies.</div>", "topic": "CHANGE OF STATE : SPECIFIC LATENT HEATS OF FUSION"}, {"id": "objective>Physics>2020 Model I>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When water is boiling, it </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Gets hotter </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increases in mass</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Decreases in mass </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Changes to steam</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When water is boiling, i.e when it is at the boiling point, its temperature does not change and its mass remains constant (since boiling is a physical change), but it changes to steam (gaseous state). </div>", "topic": "CHANGE OF STATE : EVAPORATION AND BOILING"}, {"id": "objective>Physics>2020 Model I>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following phenomena cannot be explained by molecular theory of matter?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Expansion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Conduction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Convection </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Radiation</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As radiation is a method of heat transfer by an invisible electromagnetic wave . It is not due to the movement of molecules or electrons as in conduction or the movement of the body itself as in convection. Expansion is the increase in size of a body when heated due to the increase in the amplitude of vibration of molecules. <br/> Evaporation is the change from liquid to gas by the movement of high speed molecules.</div>", "topic": "STRUCTURE OF MATTER AND KINETIC THEORY : MOLECULAR NATURE OF MATTER"}, {"id": "objective>Physics>2020 Model I>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following give rise to stationary wave? <br/> I. Two plane progressive waves travelling in opposite directions  <br/> II Two plane progressive waves travelling in the same direction <br/> III Waves of the same amplitude and frequency <br/> IV Waves which interfere</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">I and II only</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I,III and IV </div>", "<div style=\"font-family:Cambria;font-size:17px;\">II,III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and IV only</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">As stationary wave is due to the interference of two identical waves (the same amplitude and frequency) which travel in opposite direction</div>", "topic": "WAVES : CHARACTERISTICS/PROPERTIES"}, {"id": "objective>Physics>2020 Model I>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A string of length 1.0m vibrates in 10loops. If the total mass of the string is 1.0 ∗ 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>kg and the tension in it is 10N; calculate the frequency of the vibration.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">50Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">250Hz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">500Hz</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2020 Model I/phy2019.jpg\" style=\"position:relative;max-width:100%;\"/> <br/>  <br/> f=<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2l</span> &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">T</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">m</span>&nbsp;</span> <br/>  <br/> l=1m, T=10N,  m=10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> <br/>  <br/> f=<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2× 1</span> &radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">10</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></span>&nbsp;</span> <br/>  <br/> f=<span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">2</span>&radic;<span style=\"margin: 0;padding:0;border-top:solid black 1px;\">10000&nbsp;</span> <br/> f=100/2 = 50Hz <br/> for 10 loops, f=50×10 = 500Hz</div>", "topic": "PROPAGATION OF SOUND WAVES"}, {"id": "objective>Physics>2020 Model I>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A ray of light falls on a plane mirror so that the reflected ray makes an angle of 20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> with the incident ray. The mirror is turned about an axis to the right angles to the plane of the rays through an angle of 15<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>. What are now the possible angles between the incident ray and the new reflected ray?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>,20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">15<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>,10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">15<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>,20<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>  </div>", "<div style=\"font-family:Cambria;font-size:17px;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>,50<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>  </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagrammatically, <br/> <img src=\"2020 Model I/phy2020.jpg\" style=\"position:relative;max-width:100%;\"/> <br/> Draw the normal line in-between to set the angle of incidence at 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> and the angle of reflection at 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>, since i = r(law of reflection) <br/>  <img src=\"2020 Model I/phy2020s.jpg\" style=\"position:relative;max-width:100%;\"/> <br/>  Angle of rotation,θ=15<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> <br/> Since the mirror is rotated, the angle between the incident ray and the reflected is likely to change. <br/> When turned anticlockwise, angle between the rays = <br/> 2i + 2θ=2(10) + 2(15) = 20 + 30 = 50<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> <br/> When turned clockwise, angle between the rays <br/> 2i + 2θ=2(10) - 2(15) = 20 - 30 = -10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> <br/> OR <br/> 2θ - 2i = 2(15) - 2(10) = 30 - 20 =10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> <br/> ⇒The possible angles are (10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>,50<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>) <br/>  </div>", "topic": "REFLECTION OF LIGHT AT PLANE AND CURVED SURFACES"}, {"id": "objective>Physics>2020 Model I>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A ray of light is incident on the surface of water at an angle of 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span>. Calculate the deviation suffered by the ray in water-(n<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">w</span> = 1.33) <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">15<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">19.5<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">15.7<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The question asks us tp calculate the deviation suffered by the ray. <br/> Deviation, d=i-r <br/> N.B i ≻ r (since it is travelling from a less dense medium, i.e air to a dense medium, I.e water) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">recall:</td><td style=\"text-align:center;\">n=</td><td style=\"text-align:center;\">sini<hr size=\"1\" />sinr</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Sinr</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">sini<hr size=\"1\" />n</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Sinr=</td><td style=\"text-align:center;\">sin(30)<hr size=\"1\" />1.33</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.5<hr size=\"1\" />1.33</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.3759</td></tr></table></div> <br/> Sinr= 0.3759 <br/> r=sin<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>(0.3759) <br/> r=22.1<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> <br/> d= i-r = 30<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> - 22.1<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> = 7.9<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">∘</span> = 8.0 <br/>  <br/>  <br/>  <br/> </div>", "topic": "REFRACTION OF LIGHT THROUGH : PLANE AND CURVED SURFACE"}, {"id": "objective>Physics>2020 Model I>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A person with maximum distance of vision 10cm uses a diverging lens of focal length 15cm as a magnifying glass. What is the magnification when the lens is held close to the eye</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2<hr size=\"1\" />3</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">-1<hr size=\"1\" />3</td></tr></table></div></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">5<hr size=\"1\" />3</td></tr></table></div></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Image distance, V= -10cm (Image at the least or greatest distinct of vision is virtual) <br/> f= -15cm(for diverging lens) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">Recall</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">f<hr size=\"1\" />u-f</td><td style=\"text-align:center;\">Or</td><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v-f<hr size=\"1\" />f</td><td style=\"text-align:center;\">Or</td><td style=\"text-align:center;\">m</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">v<hr size=\"1\" />f</td><td style=\"text-align:center;\">-1</td></tr></table></div>] <br/> Based on the parameters given, we are applying the third one. <br/> v=-10cm; f= -15cm <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m=</td><td style=\"text-align:center;\">-19<hr size=\"1\" />-15</td><td style=\"text-align:center;\">-1</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m=</td><td style=\"text-align:center;\">2<hr size=\"1\" />3</td><td style=\"text-align:center;\">-1</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">m=</td><td style=\"text-align:center;\">-1<hr size=\"1\" />3</td></tr></table></div></div>", "topic": "OPTICAL INSTRUMENTS : NEAR AND FAR POINTS"}, {"id": "objective>Physics>2020 Model I>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram in the figure above shows the lens arrangement in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Compound microscope</div>", "<div style=\"font-family:Cambria;font-size:17px;\">An astronomical telescope</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A binocular</div>", "<div style=\"font-family:Cambria;font-size:17px;\">A periscope</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Telescope is used for a far or distant object i.e objects from parallel rays as indicated in the diagram. A microscope is used for near objects. </div>", "topic": "OPTICAL INSTRUMENTS"}, {"id": "objective>Physics>2020 Model I>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A poster has a red letter P on a white background When it is viewed through a blue transparent screen an observer would see a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">magenta P on a blue background</div>", "<div style=\"font-family:Cambria;font-size:17px;\">magenta P on a blue-black background</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Black P on a blue background </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Black P on a greenish- white background </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Red letter P on white background = R$W <br/> When viewed in blue light, <br/> Red + Blue = ROYGBIV + Blue = Blue (as blue is common) <br/> Hence,Red letter will look black while the white background becomes blue, i.e black letter on blue background.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS : COLOUR MIXING"}, {"id": "objective>Physics>2020 Model I>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following colours of light will give white light on mixing?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Red and Yellow </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Red and Magenta</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Magenta and green</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Yellow and green</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">White light is made up of all the colors of the visible light spectrum, which includes red, green, and blue light. When these primary colors are mixed together in equal intensities, they create white light. Therefore, none of the options individually can create white light. However, magenta is a secondary color made by combining blue and red, and green is a primary color. So, combining magenta and green can create white light.</div>", "topic": "DISPERSION OF LIGHT AND COLOURS : COLOUR MIXING"}, {"id": "objective>Physics>2020 Model I>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">As a positively charged rod is brought nearer to the top cap of a positively charged gold leaf electroscope, the divergence of the leaves will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase to zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Steadily increase </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Decrease to zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remain constant</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Since similar charges produce increase in divergence in a gold leaf electroscope, The divergence increases as the rod gets nearer and nearer the cap.</div>", "topic": "ELECTROSTATICS : ELECTROSCOPE"}, {"id": "objective>Physics>2020 Model I>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The equivalent capacitance for the circuit drawn is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">18μF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4μF <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2μF <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">12μF <br/> </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Equilvalent capacitance= Total capacitance  <br/> Recall:Two capacitors, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> and C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> connected in series will have equilvalent = <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span></td><td style=\"text-align:center;\">--------1</td></tr></table></div> <br/> Recall;Two capacitors,C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>  and C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> connected in parallel will have equilvalent =C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>  + C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>= C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span> <br/> The 5μF and 7μF capacitors  <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span> = 5+7= 12μF <br/> Hence the new arrangement is  <br/> <img src=\"2020 Model I/phy2027s.jpg\" style=\"position:relative;max-width:100%;\"/> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />6</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />12</td><td style=\"text-align:center;\"> <br/> </td></tr></table></div> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12∗6<hr size=\"1\" />12+6</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">72<hr size=\"1\" />18</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">4μF</td></tr></table></div> </div>", "topic": "CAPACITORS : CAPACITORS IN SERIES AND PARALLEL"}, {"id": "objective>Physics>2020 Model I>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The point at which the resultant magnetic flux density is zero is called </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">zero point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">flux point </div>", "<div style=\"font-family:Cambria;font-size:17px;\">neutral point</div>", "<div style=\"font-family:Cambria;font-size:17px;\">magnetic point</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Neutral point is the point with zero resultant magnetic flux density <br/> Neutral point is also the point with equal and opposite concentration of fields <br/> The region with greater concentration of fields in the same direction is called maximum density point</div>", "topic": "MAGNETS AND MAGNETIC FIELDS : FLUX AND FLUX DENSITY"}, {"id": "objective>Physics>2020 Model I>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following statements is correct about the earth's magnetic field?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The angle of dip is the angle which freely suspended magnet makes with the vertical </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The angle of declination is the angle between the magnetic meridian and geographic meridian.</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The angle of declination is the angle which magnetic compass makes with the magnetic meridian</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The angle of inclination is the difference between the angle of dip and the angle of declination</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The angle of dip or inclination is the angle between the horizontal and the direction of the magnetic field or the direction of a freely suspended needle in the magnetic meridian. <br/> Angle of declination is the angle between the magnetic meridian and the geographic meridian</div>", "topic": "MAGNETS AND MAGNETIC FIELDS : EARTH’S MAGNETIC FIELD"}, {"id": "objective>Physics>2020 Model I>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A simple cell with mercury-almagamated zinc electrode prevents </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">local action</div>", "<div style=\"font-family:Cambria;font-size:17px;\">polarisation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">buckling</div>", "<div style=\"font-family:Cambria;font-size:17px;\">degradation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Mercury almagamated zinc electrode is a negative pole of zinc that has been washed in H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> and rubbed with a globule of mercury to prevent local action</div>", "topic": "ELECTRIC CELLS"}, {"id": "objective>Physics>2020 Model I>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A cell has an  e.m.f of 1.5V and internal resistance of 1Ω and is connected to two resistances of 2Ω and 3Ω in series. Find the potential difference across the end of the 2Ω resistance. <br/> </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.25v</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.5v</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3.0v</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.50v</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diagrammatically, the question can be represented as thus; <br/> <img src=\"2020 Model I/phy2031.jpg\" style=\"position:relative;max-width:100%;\"/> <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">T</span>= R= 2Ω +3Ω = 5Ω  <br/> E= 1.5V, r= 1.0Ω  <br/> Recall: E= I(R+r)-----------------1 <br/> V=p.d= IR---------------2 <br/> from 1 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I=</td><td style=\"text-align:center;\">E<hr size=\"1\" />R+r</td><td style=\"text-align:center;\">-----------------3</td></tr></table></div> <br/> N.B The voltage/p.d across a resistor x <br/> =V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span> =IR<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">x</span> <br/> ∴The p.d across the resistor  <br/> = V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2Ω </span>=I ∗ 2-------------------4 <br/> from 3,  <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I=</td><td style=\"text-align:center;\">1.5<hr size=\"1\" />5+1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1.5<hr size=\"1\" />6</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">0.25A</td></tr></table></div> <br/> from 4, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2Ω </span>= 0.25 ∗ 2 = 0.50v </div>", "topic": "CURRENT ELECTRICITY"}, {"id": "objective>Physics>2020 Model I>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Calculate the current in the 3Ω resistor shown in the diagram above   </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.0A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.3A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.0A</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Since the resistors are connected in parallel, they will have the same voltage but different current <br/> For resistance in parallel <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span></td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></td><td style=\"text-align:center;\"> <br/> </td></tr></table></div>=<div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />3</td><td style=\"text-align:center;\">+</td><td style=\"text-align:center;\">1<hr size=\"1\" />4 <br/> </td></tr></table></div><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">6+4+3<hr size=\"1\" />12</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">1<hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">13<hr size=\"1\" />12 <br/> </td></tr></table></div><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12<hr size=\"1\" />13Ω</td></tr></table></div> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span>=IR<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span>-------------ohm's law <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span>=</td><td style=\"text-align:center;\">13(12)<hr size=\"1\" />13 <br/> </td></tr></table></div> <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">e</span> =12V [effective voltage which is also common] <br/> Current in the 3Ω resistor <br/> Since the voltage in each of the resistors is equal to the effective voltage;12V=V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3Ω</span>=12V = I ∗3Ω <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">12V<hr size=\"1\" />3Ω</td></tr></table></div>=4.0A</div>", "topic": "CURRENT ELECTRICITY : OHM’S LAW~~CURRENT ELECTRICITY : RESISTANCE IN SERIES AND IN PARALLEL"}, {"id": "objective>Physics>2020 Model I>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 24V battery of internal resistance of 0.75Ω delivers current through an external load of 1.25Ω. What is the power supplied?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">72.0W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">28.8W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">12.0W</div>", "<div style=\"font-family:Cambria;font-size:17px;\">180W</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given <br/> E=24V <br/> r=0.75Ω <br/> R= 1.25Ω <br/> P=? <br/>  <img src=\"2020 Model I/phy2033.jpg\" style=\"position:relative;max-width:100%;\"/> <br/> Recall; E=I(R+r)-----------1 <br/> P= I<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>R---------------2 <br/> FROM 1 <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">E<hr size=\"1\" />R+R <br/> </td></tr></table></div><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">∴P=</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">E<hr size=\"1\" />R+r</td><td style=\"text-align:center;\">)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">∗</td><td style=\"text-align:center;\">R <br/> </td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P=</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">24<hr size=\"1\" />1.25+0.75</td><td style=\"text-align:center;\">)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">∗</td><td style=\"text-align:center;\">1.25</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">P=</td><td style=\"text-align:center;\">(</td><td style=\"text-align:center;\">24<hr size=\"1\" />2.0</td><td style=\"text-align:center;\">)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">∗</td><td style=\"text-align:center;\">1.25</td></tr></table></div> <br/> P= (12)<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> ∗ 1.25 <br/> P= 144 ∗1.25 <br/> P= 180.0</div>", "topic": "ELECTRICAL ENERGY AND POWER"}, {"id": "objective>Physics>2020 Model I>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/jpeg;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the diagram above, a straight vertical wire is placed between two opposite magnetic poles which are separated horizontally by a short distance. If a current is passed down the wire, in which direction will the wire move?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Towards the observer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Away from the observer </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Towards the N pole </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Upwards <br/> </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To determine the direction in which the wire will move, we can use Fleming's Left-Hand Rule, which applies to the motor effect. According to this rule: <br/>  <br/> The First finger points in the direction of the Magnetic Field (from North to South). <br/> The Second finger points in the direction of the Current (conventional current, from positive to negative). <br/> The Thumb shows the direction of the Force (Motion). <br/>  <br/> Step 1: Determine the Current Direction in the Vertical Wire <br/> The battery polarity shows that current flows from the positive terminal (top side) to the negative terminal (bottom side). <br/> Since the current is moving clockwise, it means that in the vertical section of the wire, the current must be flowing upward. <br/>  <br/> Step 2: Apply Fleming's Left-Hand Rule <br/> Fleming's Left-Hand Rule states: <br/>  <br/> First finger → points in the direction of the Magnetic Field (from North to South). <br/> Second finger → points in the direction of the Current (conventional current, which we determined to be upward in the vertical wire). <br/> Thumb → shows the direction of Force (Motion). <br/>  <br/> Step 3: Determine the Direction of Motion <br/> Magnetic field (First finger): From N to S (horizontally). <br/> Current (Second finger): Upward. <br/> Thumb (Force direction): Into the page (away from the observer). <br/>  <br/> Conclusion: <br/> The wire will move away from the observer. <br/>  <br/> Correct answer: Away from the observer.</div>", "topic": "FORCE ON A CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD"}, {"id": "objective>Physics>2020 Model I>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following devices in their common form will not function on a steady direct current?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Electric bell</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Filament lamp</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Transformer</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Electric heating element</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A transformer will not function on a steady direct current. Transformers work on the principle of electromagnetic induction, which requires a changing magnetic field. In a direct current, the current is constant, and hence the magnetic field is also constant. Therefore, a transformer cannot function on a steady direct current.</div>", "topic": "ELECTROMAGNETIC INDUCTION : TRANSFORMERS"}, {"id": "objective>Physics>2020 Model I>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Carbon particles are used in carbon microphones because </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">They amplify the sound</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They are good conductors</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Their resistance changes with temperature </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Their resistance changes with pressure</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The electrical resistance of the carbon granules depends on the compression (pressure exerted) on the granules. <br/> The carbon granules are compressed between two carbon blocks when someone speaks and the sound vibrates the diaphragm</div>", "topic": "MAGNETIC FIELD : CARBON MICROPHONE"}, {"id": "objective>Physics>2020 Model I>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A 120v, 60/⊼ a.c source is connected across a 2μF capacitor. Calculate the current passing through the circuit. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">4.9 ∗ 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>A</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.9 ∗ 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>A <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.2 ∗ 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>A <br/> </div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0 ∗ 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span>A <br/> </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Parameters given <br/> V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">rms</span>= 120v <br/> frequency, f =60/⊼Hz <br/> Capacitance, C= 2μF <br/> Current, I=? <br/> Since A.C source is connected to a capacitor, <br/> Recall, V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">rms</span>=I ∗ C-------------1 Ohms law <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">1<hr size=\"1\" />2⊼f</td><td style=\"text-align:center;\">-----------2</td><td style=\"text-align:center;\"> <br/> </td></tr></table></div> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">=I=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">rms</span><hr size=\"1\" />X<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">c</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">rms</span></td><td style=\"text-align:center;\">∗</td><td style=\"text-align:center;\">2⊼fc</td><td style=\"text-align:center;\">-----------*</td><td style=\"text-align:center;\"></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">I=</td><td style=\"text-align:center;\">120</td><td style=\"text-align:center;\">∗</td><td style=\"text-align:center;\">2</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">∗</td><td style=\"text-align:center;\">⊼</td><td style=\"text-align:center;\">∗</td><td style=\"text-align:center;\">60<hr size=\"1\" />⊼</td><td style=\"text-align:center;\">∗</td><td style=\"text-align:center;\">2</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">∗</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-6</span> <br/> </td><td style=\"text-align:center;\"></td></tr></table></div> <br/> I= 2.88  ∗  10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span> A=2.9  ∗ 10<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-2</span></div>", "topic": "SIMPLE A. C. CIRCUITS : CAPACITOR - CAPACITIVE REACTANCE"}, {"id": "objective>Physics>2020 Model I>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In alternating current theory, the units of impedance, r.m.c voltage and resonance frequency are respectively equal to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Volt,Ampere, and Hertz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ohm,Volt and Hertz</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Watt, Ohm and Radian</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Ohm, Hertz and Joule</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Impedance is measured in Ohm <br/> r.m.s voltage is measured in volt <br/> resonance frequency is measured in Hertz</div>", "topic": "SIMPLE A. C. CIRCUITS : RESONANCE AND RESONANCE FREQUENCY"}, {"id": "objective>Physics>2020 Model I>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The breaking up of positive columns in a discharge tube into alternating bright and dark segment is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">wave</div>", "<div style=\"font-family:Cambria;font-size:17px;\">striation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">thermionic emission</div>", "<div style=\"font-family:Cambria;font-size:17px;\">field emission</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Striation is the breaking up of a positive column in a discharge tube into alternating bright and dark segments rather than filling the rest space of the discharge tube</div>", "topic": "CONDUCTION OF ELECTRICITY THROUGH : GASES"}, {"id": "objective>Physics>2020 Model I>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An atom is usually electrically neutral because it contains equal numbers of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Protons and neutrons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Protons and electrons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Neutrons and electrons</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Photons and proton</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An atom is usually electrically neutral because it contains equal numbers of protons and electrons. Protons carry a positive charge and electrons carry a negative charge. When an atom has an equal number of protons and electrons, the positive and negative charges balance out, making the atom electrically neutral.</div>", "topic": "ELEMENTARY MODERN PHYSICS : ELEMENTARY STRUCTURE OF THE ATOM"}];
